import openpyxl
from openpyxl.cell.rich_text import CellRichText, TextBlock
wb = openpyxl.load_workbook('input.xlsx', rich_text=True)
ws = wb['Sheet1']

# Check if cells have rich text (partial formatting)
for row in range(2, 35):
    cell = ws.cell(row=row, column=56)
    val = cell.value
    if val is not None:
        if isinstance(val, CellRichText):
            print(f'Row {row}: RICH TEXT')
            for part in val:
                if isinstance(part, TextBlock):
                    print(f'  TextBlock: text={repr(part.text)}, bold={part.font.bold if part.font else None}, color={part.font.color if part.font else None}')
                else:
                    print(f'  Plain: {repr(part)}')
        else:
            print(f'Row {row}: plain string = {repr(val)}, font bold={cell.font.bold}, color={cell.font.color}')
