import zipfile, xml.etree.ElementTree as ET

ns = {'s': 'http://schemas.openxmlformats.org/spreadsheetml/2006/main'}

with zipfile.ZipFile('input.xlsx') as z:
    with z.open('xl/worksheets/sheet1.xml') as f:
        tree = ET.parse(f)
        root = tree.getroot()

        styles = {}
        rows = root.findall('.//s:sheetData/s:row', ns)
        for row in rows:
            row_num = int(row.get('r'))
            for cell in row.findall('s:c', ns):
                ref = cell.get('r', '')
                if ref.startswith('BD'):
                    s = cell.get('s', '0')
                    t_elem = cell.find('.//s:t', ns)
                    text = t_elem.text if t_elem is not None else ''
                    styles.setdefault(s, [])
                    styles[s].append((row_num, text[:50]))

        for s, items in sorted(styles.items()):
            print(f'Style {s}: {len(items)} cells')
            for row_num, text in items[:3]:
                print(f'  Row {row_num}: {text}')
            if len(items) > 3:
                print(f'  ... and {len(items)-3} more')
